558→    sessionId: effectiveSessionId,
559→    taskId: identitySignals.taskId,
560→    policyDecision,
561→    conversationId,
562→    ...(injectionResult ? {
563→      intelligenceMetadata: buildIntelligenceMetadata(injectionResult),
564→    } : {}),
