568→// ---------------------------------------------------------------------------
569→// Handler Factory
570→// ---------------------------------------------------------------------------
571→
572→export function createAnthropicProxyHandler(
573→  deps: ServerDependencies,
574→): (request: Request) => Promise<Response> {
575→  const workspaceCache: WorkspaceCache = new Map();
576→  const rateLimiterState: RateLimiterState = createRateLimiterState();
577→  const spendCache: SpendCache = new Map();
578→  const noPolicyWarnedWorkspaces = new Set<string>();
579→  const contextCache: ContextCache = createContextCache(300); // default TTL, overridden per-workspace
580→
581→  // Proxy auth: per-handler cache + DB lookup function (not module-level singletons)
582→  const proxyTokenCache: TokenCache = createTokenCache();
583→  const lookupProxyToken: LookupProxyToken = createLookupProxyToken(deps.surreal);
584→
585→  // Periodic pruning of stale rate limiter entries to prevent unbounded Map growth.
586→  // unref() ensures this interval does not keep the process alive on shutdown.
587→  const pruneInterval = setInterval(
588→    () => {
589→      pruneStaleEntries(rateLimiterState, Date.now());
590→      const nowMs = Date.now();
591→      for (const [key, entry] of proxyTokenCache) {
592→        if (nowMs >= entry.expiresAt) proxyTokenCache.delete(key);
593→      }
594→    },
595→    5 * 60 * 1000,
596→  );
597→  pruneInterval.unref();
598→
599→  const anthropicApiUrl = deps.config.anthropicApiUrl;
600→
601→  return async (request: Request): Promise<Response> => {
602→    const startedAt = performance.now();
603→    const url = new URL(request.url);
604→    const upstreamPath = url.pathname.replace(/^\/proxy\/llm\/anthropic/, "");
605→    const upstreamUrl = `${anthropicApiUrl}${upstreamPath}`;
606→    const isCountTokens = isCountTokensRequest(url.pathname);
607→
608→    // --- Step 1: Parse request body (malformed body forwarded as-is) ---
609→    const body = await request.text();
610→    const parsed = tryParseRequestBody(body);
611→    const isStreaming = parsed?.stream === true;
612→
613→    // --- Step 1.5: Brain auth resolution (dual-mode) ---
614→    let brainAuthResult: ProxyAuthResult | undefined;
615→    let authMode: AuthMode = { mode: "direct" };
616→
617→    try {
618→      brainAuthResult = await resolveProxyAuth(
619→        request.headers,
620→        lookupProxyToken,
621→        proxyTokenCache,
622→      );
623→    } catch (error) {
624→      if (error instanceof ProxyAuthError) {
625→        return jsonResponse(
626→          { error: { type: "authentication_error", message: error.message } },
627→          401,
628→        );
629→      }
630→      throw error;
631→    }
632→
633→    if (brainAuthResult) {
634→      // Brain auth mode: server provides API key
635→      const serverApiKey = deps.config.anthropicApiKey;
636→      if (!serverApiKey) {
637→        logError("proxy.anthropic.no_server_api_key", "Server Anthropic API key not configured for Brain auth mode", undefined);
638→        return jsonResponse(
639→          { error: { type: "server_error", message: "Server Anthropic API key not configured" } },
640→          500,
641→        );
642→      }
643→      authMode = { mode: "brain", serverApiKey };
644→    }
645→
646→    // --- Step 2: Identity resolution ---
647→    // In Brain auth mode, workspace comes from the token (not from headers)
648→    const identitySignals = resolveIdentity({
649→      metadataUserId: parsed?.metadata?.user_id,
650→      workspaceHeader: brainAuthResult?.workspaceId ?? (request.headers.get("X-Brain-Workspace") ?? undefined),
651→      taskHeader: request.headers.get("X-Brain-Task") ?? undefined,
652→      agentTypeHeader: request.headers.get("X-Brain-Agent-Type") ?? undefined,
653→      sessionHeader: request.headers.get("X-Brain-Session") ?? undefined,
654→      proxyTokenIdentityId: brainAuthResult?.identityId,
655→    });
656→
657→    // --- Step 3: Session ID resolution ---
658→    // resolveSessionId returns either the header PK or the external Claude Code
659→    // session UUID. Resolve to the actual agent_session PK via DB lookup.
660→    const rawSessionId = resolveSessionId(identitySignals);
661→    const effectiveSessionId = rawSessionId
662→      ? await resolveAgentSessionId(deps.surreal, rawSessionId)
663→      : undefined;
664→
665→    // --- Step 3.5: Conversation hash resolution (pure) ---
666→    const conversationHashInput: ConversationHashInput = {
667→      systemPrompt: typeof parsed?.system === "string" ? parsed.system : undefined,
668→      systemPromptBlocks: Array.isArray(parsed?.system) ? parsed.system : undefined,
669→      messages: parsed?.messages ?? [],
670→    };
671→    const conversationHash = resolveConversationHash(conversationHashInput);
672→
673→    // --- Conversation upsert (async, non-blocking) ---
674→    let conversationId: string | undefined;
675→    if (conversationHash && identitySignals.workspaceId) {
676→      try {
677→        const conversationRecord = await upsertConversation(
678→          {
679→            conversationId: conversationHash.conversationId,
680→            workspaceId: identitySignals.workspaceId,
681→            title: conversationHash.title,
682→          },
683→          { surreal: deps.surreal },
684→        );
685→        if (conversationRecord) {
686→          conversationId = conversationHash.conversationId;
687→        }
688→      } catch (error) {
689→        logWarn("proxy.anthropic.conversation_upsert_failed", "Conversation upsert failed — continuing without conversation link", {
690→          error: String(error),
691→        });
692→      }
693→    }
694→
695→    // --- Workspace validation (non-blocking) ---
696→    if (identitySignals.workspaceId) {
697→      const isValid = await validateWorkspace(
698→        deps.surreal,
699→        identitySignals.workspaceId,
700→        workspaceCache,
701→      );
702→      if (!isValid) {
703→        logWarn("proxy.anthropic.invalid_workspace", "Workspace not found in database", {
704→          workspaceId: identitySignals.workspaceId,
705→        });
706→      }
707→    }
708→
709→    // --- Step 4: Policy evaluation ---
710→    let policyResult: ProxyPolicyResult | undefined;
711→    if (parsed?.model && !isCountTokens) {
712→      const policyDeps: ProxyPolicyDependencies = {
713→        surreal: deps.surreal,
714→        inflight: deps.inflight,
715→        rateLimiterState,
716→        spendCache,
717→      };
718→
719→      policyResult = await evaluateProxyPolicy(
720→        {
721→          workspaceId: identitySignals.workspaceId ?? "",
722→          agentType: identitySignals.agentType,
723→          model: parsed.model,
724→        },
725→        policyDeps,
726→        noPolicyWarnedWorkspaces,
727→      );
728→
729→      if (policyResult.decision !== "allow") {
730→        return buildPolicyDenialResponse(policyResult);
731→      }
732→    }
733→
734→    // --- Step 5: Context injection (fail-open) ---
735→    let effectiveBody = body;
736→    let injectionResult: InjectionResult | undefined;
737→
738→    if (parsed && identitySignals.workspaceId && !isCountTokens) {
739→      try {
740→        const intelligenceConfig = await loadIntelligenceConfig(deps.surreal, identitySignals.workspaceId);
741→        const contextResult = await runContextInjection(
742→          deps,
743→          identitySignals.workspaceId,
744→          parsed,
745→          body,
746→          contextCache,
747→          intelligenceConfig,
748→        );
749→        effectiveBody = contextResult.body;
750→        injectionResult = contextResult.injectionResult;
751→        if (intelligenceConfig.contextInjectionEnabled) {
752→          logInfo("proxy.context_injection.result", "Context injection completed", {
753→            workspace_id: identitySignals.workspaceId,
754→            injected: injectionResult?.injected ?? false,
755→            decisions: injectionResult?.decisionsCount ?? 0,
756→            learnings: injectionResult?.learningsCount ?? 0,
757→            observations: injectionResult?.observationsCount ?? 0,
758→          });
759→        }
760→      } catch (error) {
761→        // Fail-open: log warning and continue with original body
762→        logWarn("proxy.context_injection.failed", "Context injection failed, forwarding original request", {
763→          workspace_id: identitySignals.workspaceId,
764→          error: String(error),
765→        });
766→      }
767→    }
768→
769→    // --- API key validation (skip for Brain auth — server provides key) ---
770→    if (authMode.mode === "direct") {
771→      const hasApiKey = request.headers.has("x-api-key");
772→      const hasAuthHeader = request.headers.has("authorization");
773→      if (!hasApiKey && !hasAuthHeader) {
774→        return jsonResponse(
775→          { error: { type: "authentication_error", message: "Missing x-api-key or authorization header" } },
776→          401,
777→        );
778→      }
779→    }
780→
781→    // --- Build identity context for logging ---
782→    const identityContext = {
783→      user_hash: identitySignals.userHash,
784→      account_id: identitySignals.accountId,
785→      session_id: effectiveSessionId,
786→      workspace_id: identitySignals.workspaceId,
787→      task_id: identitySignals.taskId,
788→      agent_type: identitySignals.agentType,
789→      is_count_tokens: isCountTokens || undefined,
790→    };
791→
792→    logInfo("proxy.anthropic.request", "Forwarding to Anthropic", {
793→      method: request.method,
794→      url: upstreamUrl,
795→      ...identityContext,
796→    });
797→
798→    // --- Build policy decision for audit trail ---
799→    const policyDecision: PolicyDecisionLog | undefined = policyResult
800→      ? {
801→          decision: "pass",
802→          policy_refs: policyResult.decision === "allow" ? policyResult.policyIds : [],
803→          timestamp: new Date().toISOString(),
804→        }
805→      : undefined;
806→
807→    // --- Step 6: Request forwarding ---
808→    const upstreamHeaders = buildUpstreamHeaders(request, authMode);
809→
810→    let upstream: Response;
811→    try {
812→      upstream = await fetch(upstreamUrl, {
813→        method: request.method,
814→        headers: upstreamHeaders,
815→        body: request.method !== "GET" ? effectiveBody : undefined,
816→      });
817→    } catch (error) {
818→      logError("proxy.anthropic.upstream_error", "Failed to reach Anthropic API", error);
819→      return jsonResponse({ error: "upstream_unreachable", source: "proxy" }, 502);
820→    }
821→
822→    // --- Non-streaming response ---
823→    if (!isStreaming) {
824→      const responseBody = await upstream.text();
825→      const latencyMs = elapsedMs(startedAt);
826→
827→      logInfo("proxy.anthropic.response", "Anthropic response", {
828→        status: upstream.status,
829→        latency_ms: latencyMs,
830→        ...identityContext,
831→      });
832→
833→      // Async trace capture for non-streaming (skip count_tokens)
834→      if (!isCountTokens && upstream.status >= 200 && upstream.status < 300) {
835→        const traceData = extractNonStreamingUsage(responseBody, parsed?.model, latencyMs, identitySignals, effectiveSessionId, policyDecision, conversationId, injectionResult);
836→        if (traceData) {
837→          deps.inflight.track(
838→            captureTrace(traceData, { surreal: deps.surreal }).catch(() => undefined),
839→          );
840→        }
841→      }
842→
843→      return new Response(responseBody, {
844→        status: upstream.status,
845→        headers: {
846→          "Content-Type": upstream.headers.get("content-type") ?? "application/json",
847→          "Access-Control-Allow-Origin": "*",
848→        },
849→      });
850→    }
851→
852→    // --- Streaming: pipe SSE events through ---
853→    const { readable, writable } = new TransformStream<Uint8Array>();
854→    const writer = writable.getWriter();
855→    const reader = upstream.body!.getReader();
856→    const decoder = new TextDecoder();
857→
858→    const streamContext: StreamContext = {
859→      model: parsed?.model,
860→      inputTokens: 0,
861→      outputTokens: 0,
862→      cacheCreationTokens: 0,
863→      cacheReadTokens: 0,
864→      stopReason: undefined,
865→    };
866→
867→    (async () => {
868→      try {
869→        let buffer = "";
870→        while (true) {
871→          const { done, value } = await reader.read();
872→          if (done) break;
873→
874→          await writer.write(value);
875→
876→          buffer += decoder.decode(value, { stream: true });
877→          buffer = extractSSEUsage(buffer, streamContext);
878→        }
879→      } catch (error) {
880→        logError("proxy.anthropic.stream_error", "SSE relay error", error);
881→      } finally {
882→        await writer.close();
883→
884→        const latencyMs = elapsedMs(startedAt);
885→
886→        logInfo("proxy.anthropic.response", "Anthropic stream complete", {
887→          model: streamContext.model,
888→          input_tokens: streamContext.inputTokens,
889→          output_tokens: streamContext.outputTokens,
890→          cache_creation_tokens: streamContext.cacheCreationTokens,
891→          cache_read_tokens: streamContext.cacheReadTokens,
892→          stop_reason: streamContext.stopReason,
893→          latency_ms: latencyMs,
894→          ...identityContext,
895→        });
896→
897→        // Async trace capture for streaming (skip count_tokens)
898→        if (!isCountTokens && streamContext.model) {
899→          const traceData = buildStreamingTraceData(
900→            streamContext, latencyMs, identitySignals,
901→            effectiveSessionId, policyDecision, conversationId, injectionResult,
902→          );
903→          deps.inflight.track(
904→            captureTrace(traceData, { surreal: deps.surreal }).catch(() => undefined),
905→          );
906→        }
907→      }
908→    })();
909→
910→    return new Response(readable, {
911→      status: upstream.status,
912→      headers: {
913→        "Content-Type": "text/event-stream",
914→        "Cache-Control": "no-cache",
915→        "Connection": "keep-alive",
916→        "X-Accel-Buffering": "no",
917→        "Access-Control-Allow-Origin": "*",
918→      },
